import{_ as t,o as e,c as i,a5 as n}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"ADC 电流采样时序 — 避开开关噪声的最佳采样时机","description":"","frontmatter":{"title":"ADC 电流采样时序 — 避开开关噪声的最佳采样时机","date":"2026-07-02T00:00:00.000Z","section":"电机控制","chapter":"02-Simulations","chapterTitle":"仿真专题","category":"电机控制","tags":["imported"],"source":"motor","sourcePath":"frontend/src/components/simulations/SamplingTimingSim.vue","status":"learning","visibility":"public","summary":"Imported from frontend/src/components/simulations/SamplingTimingSim.vue","chapterOrder":20},"headers":[],"relativePath":"content/motor/simulations/SamplingTimingSim.md","filePath":"content/motor/simulations/SamplingTimingSim.md","lastUpdated":null}'),o={name:"content/motor/simulations/SamplingTimingSim.md"};function r(s,a,m,l,c,d){return e(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="adc-电流采样时序-—-避开开关噪声的最佳采样时机" tabindex="-1">ADC 电流采样时序 — 避开开关噪声的最佳采样时机 <a class="header-anchor" href="#adc-电流采样时序-—-避开开关噪声的最佳采样时机" aria-label="Permalink to &quot;ADC 电流采样时序 — 避开开关噪声的最佳采样时机&quot;">​</a></h1><h4 id="adc-电流采样时序-—-避开开关噪声的最佳采样时机-1" tabindex="-1">ADC 电流采样时序 — 避开开关噪声的最佳采样时机 <a class="header-anchor" href="#adc-电流采样时序-—-避开开关噪声的最佳采样时机-1" aria-label="Permalink to &quot;ADC 电流采样时序 — 避开开关噪声的最佳采样时机&quot;">​</a></h4><h2 id="电流采样时序原理" tabindex="-1">电流采样时序原理 <a class="header-anchor" href="#电流采样时序原理" aria-label="Permalink to &quot;电流采样时序原理&quot;">​</a></h2><p>**中心对齐 PWM 的窗口：**计数器上/下计数时，比较沿分布在周期两侧；Ts/2 顶点附近通常落在零矢量中心，远离桥臂切换沿。采样窗口不是一个点，而是“ADC 孔径时间内电流足够稳定”的安全区。</p><p>**开关噪声避让：**导通/关断边沿会带来 di/dt、驱动地弹、采样电阻恢复和运放饱和尾迹。死区越长、功率级越硬，边沿后需要避让的时间越长；随机采样或连续采样很容易把尖峰当成真实电流。</p><p>**一拍延迟：**典型流程是 ADC 触发 → 采样转换 → FOC 计算 → 下一个 PWM 更新事件装载，因此本周期采到的电流通常作用到下一拍电压矢量。高速时必须用 θcomp = ωe·Tdelay 做角度前馈补偿。</p><p><strong>常见误区：</strong>“顶点采样一定最好”并不绝对；当占空比接近 0/100%、低边采样窗口消失或三电阻/单电阻拓扑不同，必须重新计算可采样窗口，必要时用双采样、相移 PWM 或重构算法。</p>',7)])])}const h=t(o,[["render",r]]);export{u as __pageData,h as default};
